import './index.less'
import { useEffect, useMemo, useState } from 'react'
import { Button, Image } from '@arco-design/web-react'
import {
  IconDown,
  IconEdit,
  IconLeft,
  IconUp,
  IconArrowLeft,
  IconArrowRight,
} from '@arco-design/web-react/icon'
import ContractorHeader from '../../../components/ContractorHeader'
import ApprovalProgressCard from '@common/components/ApprovalProgressCard'
import { useParams, useNavigate } from 'react-router-dom'
import {
  getPatrolApprovalRecord,
  getPatrolDetail,
  patrolFindingCount,
} from '@/service'
import { useRequest } from 'ahooks'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { useLocation } from 'react-router-dom'
import { ContractorApproval } from '@/constants/contractor'
import { useTranslation } from 'react-i18next'
// ─── Types ────────────────────────────────────────────────────────────────────

type Answer = 1 | 0 | null

interface AttachmentItem {
  url: string
  absUrl?: string
  name: string
}

interface Finding {
  id: string
  notesAr: string
  notesEn: string
  attachments: AttachmentItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept: string
  targetClosureDate: string
}

interface QuestionItem {
  id: string
  question: string
  answer: Answer
  findings: Finding[]
}

interface Section {
  id: string
  no: number
  title: string
  defaultOpen: boolean
  items: QuestionItem[]
}

const INSIDE_FLOORS = [
  { label: 'G', value: 0 },
  { label: 'M', value: 1 },
  { label: '1', value: 2 },
  { label: '2', value: 3 },
  { label: '3', value: 4 },
  { label: '4', value: 5 },
  { label: '5', value: 6 },
  { label: '6', value: 7 },
  { label: 'RF', value: 8 },
] as const
type FloorKey = (typeof INSIDE_FLOORS)[number]

const PARKING_SUBS = [
  { label: 'P1', value: 9 },
  { label: 'P2', value: 10 },
  { label: 'P3', value: 11 },
] as const
type ParkingKey = (typeof PARKING_SUBS)[number]

type NavSel =
  | { area: 'around' }
  | { area: 'inside'; floor: FloorKey }
  | { area: 'parking'; sub: ParkingKey }

// ─── Constants ────────────────────────────────────────────────────────────────

const classPrefix = 'ratrol-record-detail'

// ─── Approval mock data (右侧审批暂不对接) ────────────────────────────────────

// ─── AnswerBadge ──────────────────────────────────────────────────────────────

const AnswerBadge = ({ answer }: { answer: Answer }) => {
  const { t } = useTranslation(['common'])
  return (
    <div
      className={`${classPrefix}__answer-badge ${classPrefix}__answer-badge--${
        answer === 1 ? 'yes' : answer === 0 ? 'no' : ''
      }`}
    >
      {answer === 1 ? t('common:yes') : answer === 0 ? t('common:no') : '--'}
    </div>
  )
}

// ─── FindingView ──────────────────────────────────────────────────────────────

const FindingView = ({
  finding,
  index,
}: {
  finding: Finding
  index: number
}) => {
  const { t } = useTranslation(['contractorPatrolRecord', 'securityPatrol'])
  return (
    <div className={`${classPrefix}__finding`}>
      <div className={`${classPrefix}__finding-title`}>
        {t('contractorPatrolRecord:finding', { n: index + 1 })}
      </div>

      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>
          {t('securityPatrol:patrolRecords.detail.notes')}
        </span>
        <span className={`${classPrefix}__field-value`}>
          {finding.notesEn || finding.notesAr || '--'}
        </span>
      </div>

      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>
          {t('securityPatrol:patrolRecords.detail.attachment')}
        </span>
        <div className={`${classPrefix}__attachments`}>
          {finding.attachments.length > 0
            ? finding.attachments.map((att, idx) => {
                const src = att.absUrl || att.url
                return src ? (
                  <Image
                    key={idx}
                    src={src}
                    alt={att.name}
                    width={72}
                    height={72}
                    className={`${classPrefix}__attachment-img`}
                  />
                ) : (
                  <div
                    key={idx}
                    className={`${classPrefix}__attachment-placeholder`}
                  />
                )
              })
            : '--'}
        </div>
      </div>

      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>
          {t('securityPatrol:patrolRecords.detail.correctiveActions')}
        </span>
        <span className={`${classPrefix}__field-value`}>
          {finding.correctiveActionEn || finding.correctiveActionAr || '--'}
        </span>
      </div>

      <div className={`${classPrefix}__finding-row`}>
        <div className={`${classPrefix}__field`}>
          <span className={`${classPrefix}__field-label`}>
            {t('securityPatrol:patrolRecords.detail.responsibleDepartment')}
          </span>
          <span className={`${classPrefix}__field-value`}>
            {finding.dept || '--'}
          </span>
        </div>
        <div className={`${classPrefix}__field`}>
          <span className={`${classPrefix}__field-label`}>
            {t('securityPatrol:patrolRecords.detail.targetClosureDate')}
          </span>
          <span className={`${classPrefix}__field-value`}>
            {finding.targetClosureDate || '--'}
          </span>
        </div>
      </div>
    </div>
  )
}

// ─── QuestionItemView ─────────────────────────────────────────────────────────

const QuestionItemView = ({ item }: { item: QuestionItem }) => (
  <div className={`${classPrefix}__item`}>
    <div className={`${classPrefix}__item-row`}>
      <span className={`${classPrefix}__item-question`}>{item.question}</span>
      <AnswerBadge answer={item.answer} />
    </div>
    {item.answer === 0 && item.findings.length > 0 && (
      <div className={`${classPrefix}__findings`}>
        {item.findings.map((f, idx) => (
          <FindingView key={f.id} finding={f} index={idx} />
        ))}
      </div>
    )}
  </div>
)

// ─── SectionView ──────────────────────────────────────────────────────────────

const SectionView = ({ section }: { section: Section }) => {
  const { t } = useTranslation(['contractorPatrolRecord'])
  const [open, setOpen] = useState(section.defaultOpen)

  return (
    <div className={`${classPrefix}__section`}>
      <div
        className={`${classPrefix}__section-header${open ? ` ${classPrefix}__section-header--open` : ''}`}
        onClick={() => setOpen((v) => !v)}
      >
        <div>
          <div className={`${classPrefix}__section-no`}>
            {t('contractorPatrolRecord:category', { n: section.no })}
          </div>
          <div className={`${classPrefix}__section-title`}>{section.title}</div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && section.items.length > 0 && (
        <div className={`${classPrefix}__section-body`}>
          {section.items.map((item) => (
            <QuestionItemView key={item.id} item={item} />
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Main component ───────────────────────────────────────────────────────────

const PatrolRecordDetail = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const { t } = useTranslation([
    'contractorPatrolRecord',
    'securityPatrol',
    'common',
  ])
  const [navSel, setNavSel] = useState<NavSel>({ area: 'around' })
  const [findingCountData, setFindingCountData] = useState<any>()
  const [detailData, setDetailData] = useState<any>(null)
  const [metaData, setMetaData] = useState<any>(null)
  const [approveLog, setApproveLog] = useState<any>([])
  const [approveFlag, setApproveFlag] = useState<number>(0)
  const location = useLocation()
  const { status } = location?.state
  // const {}
  // ─── Sidebar data derived from patrolFindingCount ─────────────────────────

  const aroundApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 1,
  )
  const insideApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 2,
  )
  const parkingApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 3,
  )

  const getInsideFloorData = (floor: FloorKey) =>
    insideApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === floor.value,
    )

  const getParkingSubData = (sub: ParkingKey) =>
    parkingApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === sub.value,
    )

  // ─── Build sections dynamically from detail API ───────────────────────────

  const dynamicSections = useMemo((): Section[] => {
    const answerList: any[] = detailData?.patrolAnswerList ?? []
    if (!answerList.length) return []
    const map = new Map<string, Section>()
    answerList.forEach((ans: any) => {
      const key = String(ans.sectionId)
      if (!map.has(key)) {
        map.set(key, {
          id: `sec-${key}`,
          no: map.size + 1,
          title: isLanguageAR
            ? ans.sectionNameAr || ans.sectionName
            : ans.sectionName,
          defaultOpen: map.size === 0,
          items: [],
        })
      }
      const findings: Finding[] =
        ans.isSituation === 0 && ans.findings?.length
          ? ans.findings.map(
              (f: any): Finding => ({
                id: String(
                  f.correctiveActionId ?? `${ans.itemId}-${Math.random()}`,
                ),
                notesAr: f.findingRemarkAr ?? '',
                notesEn: f.findingRemark ?? '',
                attachments: (f.attachmentList ?? []).map((att: any) => ({
                  url: att.url ?? '',
                  absUrl: att.absUrl ?? '',
                  name: att.fileName ?? '',
                })),
                correctiveActionAr: f.correctiveActionAr ?? '',
                correctiveActionEn: f.correctiveAction ?? '',
                dept: isLanguageAR
                  ? f.org?.orgNameAr || f.org?.orgName || ''
                  : f.org?.orgName || '',
                targetClosureDate: f.targetClosureDate ?? '',
              }),
            )
          : []
      map.get(key)!.items.push({
        id: String(ans.itemId),
        question: isLanguageAR ? ans.itemNameAr || ans.itemName : ans.itemName,
        answer: ans.isSituation === 1 ? 1 : ans.isSituation === 0 ? 0 : null,
        findings,
      })
    })
    return Array.from(map.values())
  }, [detailData, isLanguageAR])

  const contentTitle =
    navSel.area === 'around'
      ? t('securityPatrol:patrolRecords.detail.tabs.around')
      : navSel.area === 'inside'
        ? t('contractorPatrolRecord:contentTitle.insideFloor', {
            label: navSel.floor.label,
          })
        : t('contractorPatrolRecord:contentTitle.parkingSub', {
            label: navSel.sub.label,
          })

  // ─── API calls ────────────────────────────────────────────────────────────

  const { run: runPatrolFindingCount } = useRequest(patrolFindingCount, {
    manual: true,
    onSuccess: (res: any) => {
      setFindingCountData(res)
    },
  })

  const { run: runPatrolDetail } = useRequest(getPatrolDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setDetailData(res)
      if (!metaData) setMetaData(res)
    },
  })
  const { run: runGetApprovalDetail } = useRequest(getPatrolApprovalRecord, {
    manual: true,
    onSuccess: (res: any) => {
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag)
    },
  })

  useEffect(() => {
    if (id) {
      runPatrolFindingCount({ patrolId: id })
      runPatrolDetail({ patrolId: id, type: 1, floor: -1 })
      runGetApprovalDetail({ patrolId: id })
    }
  }, [id])

  const handleNavSel = (area: string, value?: any) => {
    let type = 1
    let floor = -1
    if (area === 'around') {
      setNavSel({ area: 'around' })
    } else if (area === 'inside') {
      setNavSel({ area: 'inside', floor: value })
      type = 2
      floor = value.value
    } else if (area === 'parking') {
      setNavSel({ area: 'parking', sub: value })
      type = 3
      floor = value.value
    }
    runPatrolDetail({ patrolId: id, type, floor })
  }
  const statusColorMap: Record<number, string> = {
    0: '#86909C',
    1: '#FF7D00',
    2: '#45AD5E',
    3: '#F53F3F',
  }
  const ApprovalType: Record<number, string> = {
    0: t('securityPatrol:status.draft'),
    1: t('securityPatrol:status.underReview'),
    2: t('securityPatrol:status.approved'),
    3: t('securityPatrol:status.rejected'),
  }

  return (
    <div className={classPrefix}>
      <ContractorHeader />

      <div className={`${classPrefix}__wrapper`}>
        <div className={`${classPrefix}__card`}>
          {/* Card header */}
          <div className={`${classPrefix}__card-header`}>
            <span className={`${classPrefix}__card-title`}>
              {t('securityPatrol:patrolRecords.detail.title')}
            </span>
            {status != null && (
              <div
                className={`${classPrefix}__status-badge`}
                style={{
                  borderColor: `${statusColorMap[status]}66`,
                  background: `${statusColorMap[status]}0D`,
                }}
              >
                <span
                  className={`${classPrefix}__status-badge-dot`}
                  style={{ background: statusColorMap[status] }}
                />
                <span
                  className={`${classPrefix}__status-badge-text`}
                  style={{ color: statusColorMap[status] }}
                >
                  {ApprovalType[status as keyof typeof ApprovalType] ?? '--'}
                </span>
              </div>
            )}
          </div>

          {/* Body: left (meta + sidebar + main) + right aside */}
          <div className={`${classPrefix}__body`}>
            {/* Left column */}
            <div className={`${classPrefix}__left`}>
              {/* Meta bar */}
              <div className={`${classPrefix}__meta-bar`}>
                <div className={`${classPrefix}__meta-item`}>
                  <span className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.patrolId')}
                  </span>
                  <span className={`${classPrefix}__meta-value`}>
                    {metaData?.code ?? '--'}
                  </span>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <span className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.patrolDate')}
                  </span>
                  <span className={`${classPrefix}__meta-value`}>
                    {metaData?.patrolDate ?? '--'}
                  </span>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <span className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.shift')}
                  </span>
                  <span className={`${classPrefix}__meta-value`}>
                    {metaData?.shift === 1
                      ? t('securityPatrol:shift.day')
                      : metaData?.shift === 2
                        ? t('securityPatrol:shift.night')
                        : '--'}
                  </span>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <span className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.columns.contractor')}
                  </span>
                  <span className={`${classPrefix}__meta-value`}>
                    {isLanguageAR
                      ? metaData?.reportedByNameAr
                      : metaData?.reportedByName}
                  </span>
                </div>
                <div className={`${classPrefix}__meta-item`}>
                  <span className={`${classPrefix}__meta-label`}>
                    {t('securityPatrol:patrolRecords.detail.patrollerName')}
                  </span>
                  <span className={`${classPrefix}__meta-value`}>
                    {metaData?.inspector ?? '--'}
                  </span>
                </div>
              </div>

              {/* Inner: sidebar + main */}
              <div className={`${classPrefix}__inner`}>
                {/* Sidebar */}
                <div className={`${classPrefix}__sidebar`}>
              {/* Around the Building */}
              <div
                className={`${classPrefix}__nav-item${navSel.area === 'around' ? ` ${classPrefix}__nav-item--active` : ''}`}
                onClick={() => handleNavSel('around')}
              >
                {/* <span
                  className={`${classPrefix}__nav-dot${navSel.area === 'around' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                /> */}
                <span className={`${classPrefix}__nav-label`}>
                  {t('securityPatrol:patrolRecords.detail.tabs.around')}
                </span>
                {(aroundApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {aroundApiData.findingCount}
                  </span>
                )}
              </div>

              {/* Inside the Building group */}
              <div
                className={`${classPrefix}__nav-group-header${navSel.area === 'inside' ? ` ${classPrefix}__nav-group-header--active` : ''}`}
                onClick={() => handleNavSel('inside', INSIDE_FLOORS[0])}
              >
                {/* <span
                  className={`${classPrefix}__nav-dot${navSel.area === 'inside' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                /> */}
                <span className={`${classPrefix}__nav-label`}>
                  {t('securityPatrol:patrolRecords.detail.tabs.inside')}
                </span>
                {(insideApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {insideApiData.findingCount}
                  </span>
                )}
              </div>
              {INSIDE_FLOORS.map((floor) => {
                const floorData = getInsideFloorData(floor)
                const isActive =
                  navSel.area === 'inside' &&
                  navSel.floor?.value === floor.value
                return (
                  <div
                    key={floor.value}
                    className={`${classPrefix}__nav-child${isActive ? ` ${classPrefix}__nav-child--active` : ''}`}
                    onClick={() => handleNavSel('inside', floor)}
                  >
                    {/* <span
                      className={`${classPrefix}__nav-child-dot${isActive ? ` ${classPrefix}__nav-child-dot--active` : ''}`}
                    /> */}
                    <span className={`${classPrefix}__nav-label`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.floor', {
                        unit: floor.label,
                      })}
                    </span>
                    {(floorData?.findingCount ?? 0) > 0 && (
                      <span className={`${classPrefix}__nav-badge`}>
                        {floorData.findingCount}
                      </span>
                    )}
                  </div>
                )
              })}

              {/* Parking group */}
              <div
                className={`${classPrefix}__nav-group-header${navSel.area === 'parking' ? ` ${classPrefix}__nav-group-header--active` : ''}`}
                onClick={() => handleNavSel('parking', PARKING_SUBS[0])}
              >
                {/* <span
                  className={`${classPrefix}__nav-dot${navSel.area === 'parking' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                /> */}
                <span className={`${classPrefix}__nav-label`}>
                  {t('securityPatrol:patrolRecords.detail.tabs.parking')}
                </span>
                {(parkingApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {parkingApiData.findingCount}
                  </span>
                )}
              </div>
              {PARKING_SUBS.map((sub) => {
                const subData = getParkingSubData(sub)
                const isActive =
                  navSel.area === 'parking' && navSel.sub?.value === sub.value
                return (
                  <div
                    key={sub.value}
                    className={`${classPrefix}__nav-child${isActive ? ` ${classPrefix}__nav-child--active` : ''}`}
                    onClick={() => handleNavSel('parking', sub)}
                  >
                    {/* <span
                      className={`${classPrefix}__nav-child-dot${isActive ? ` ${classPrefix}__nav-child-dot--active` : ''}`}
                    /> */}
                    <span className={`${classPrefix}__nav-label`}>
                      {sub.label}
                    </span>
                    {(subData?.findingCount ?? 0) > 0 && (
                      <span className={`${classPrefix}__nav-badge`}>
                        {subData.findingCount}
                      </span>
                    )}
                  </div>
                )
              })}
            </div>

                {/* Main content */}
                <div className={`${classPrefix}__main`}>
                  <div className={`${classPrefix}__content-title`}>
                    {contentTitle}
                  </div>
                  <div className={`${classPrefix}__sections`}>
                    {dynamicSections.map((section) => (
                      <SectionView key={section.id} section={section} />
                    ))}
                  </div>
                </div>
              </div>{/* end __inner */}
            </div>{/* end __left */}

            {/* Right aside: approval panel */}
            <div className={`${classPrefix}__aside`}>
              <ApprovalProgressCard
                title={t('contractorPatrolRecord:inspectionApproval')}
                approveLog={approveLog}
                approveFlag={null}
                // approveFlag={1}
                moduleId=''
                moduleIdKey='patrolRecordId'
                backUrl='/contractor/list'
                approvalRejected={() => Promise.resolve()}
                approvalApproved={() => Promise.resolve()}
              />
            </div>
          </div>{/* end __body */}
          {/* Footer buttons */}
          <div className={`${classPrefix}__footer`}>
            <Button
              icon={isLanguageAR ? <IconArrowRight /> : <IconArrowLeft />}
              onClick={() => navigate(-1)}
              className='footer-back'
            >
              {t('common:btn.back')}
            </Button>
            {status === ContractorApproval.Rejected && (
              <Button
                type='primary'
                icon={<IconEdit />}
                onClick={() => navigate(`/contractor/addOrEdit/${id}`)}
              >
                {t('common:btn.edit')}
              </Button>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

export default PatrolRecordDetail

import './index.less'
import { useEffect, useMemo, useState } from 'react'
import { Button, Image } from '@arco-design/web-react'
import {
  IconDown,
  IconEdit,
  IconLeft,
  IconUp,
} from '@arco-design/web-react/icon'
import ContractorHeader from '../../../../Login/components/ContractorHeader'
import ApprovalProgressCard from '@common/components/ApprovalProgressCard'
import { useParams, useNavigate } from 'react-router-dom'
import {
  getPatrolApprovalRecord,
  getPatrolDetail,
  patrolFindingCount,
} from '@/service'
import { useRequest } from 'ahooks'
import { getLanguage } from '@common/utils/localStorage'
import { LanguageEnum } from '@common/constants/language'
import { useLocation } from 'react-router-dom'
import { ContractorApproval } from '@/constants/contractor'
import { useTranslation } from 'react-i18next'
// ─── Types ────────────────────────────────────────────────────────────────────

type Answer = 1 | 0 | null

interface AttachmentItem {
  url: string
  absUrl?: string
  name: string
}

interface Finding {
  id: string
  notesAr: string
  notesEn: string
  attachments: AttachmentItem[]
  correctiveActionAr: string
  correctiveActionEn: string
  dept: string
  targetClosureDate: string
}

interface QuestionItem {
  id: string
  question: string
  answer: Answer
  findings: Finding[]
}

interface Section {
  id: string
  no: number
  title: string
  defaultOpen: boolean
  items: QuestionItem[]
}

const INSIDE_FLOORS = [
  { label: 'G', value: 0 },
  { label: 'M', value: 1 },
  { label: '1', value: 2 },
  { label: '2', value: 3 },
  { label: '3', value: 4 },
  { label: '4', value: 5 },
  { label: '5', value: 6 },
  { label: '6', value: 7 },
  { label: 'RF', value: 8 },
] as const
type FloorKey = (typeof INSIDE_FLOORS)[number]

const PARKING_SUBS = [
  { label: 'P1', value: 9 },
  { label: 'P2', value: 10 },
  { label: 'P3', value: 11 },
] as const
type ParkingKey = (typeof PARKING_SUBS)[number]

type NavSel =
  | { area: 'around' }
  | { area: 'inside'; floor: FloorKey }
  | { area: 'parking'; sub: ParkingKey }

// ─── Constants ────────────────────────────────────────────────────────────────

const classPrefix = 'ratrol-record-detail'

// ─── Approval mock data (右侧审批暂不对接) ────────────────────────────────────

// ─── AnswerBadge ──────────────────────────────────────────────────────────────

const AnswerBadge = ({ answer }: { answer: Answer }) => {
  const { t } = useTranslation(['common'])
  return (
    <div
      className={`${classPrefix}__answer-badge ${classPrefix}__answer-badge--${
        answer === 1 ? 'yes' : answer === 0 ? 'no' : ''
      }`}
    >
      {answer === 1 ? t('common:yes') : answer === 0 ? t('common:no') : '--'}
    </div>
  )
}

// ─── FindingView ──────────────────────────────────────────────────────────────

const FindingView = ({
  finding,
  index,
}: {
  finding: Finding
  index: number
}) => {
  const { t } = useTranslation(['contractorPatrolRecord', 'securityPatrol'])
  return (
    <div className={`${classPrefix}__finding`}>
      <div className={`${classPrefix}__finding-title`}>{t('contractorPatrolRecord:finding', { n: index + 1 })}</div>

      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>{t('securityPatrol:patrolRecords.detail.notes')}</span>
        <span className={`${classPrefix}__field-value`}>
          {finding.notesEn || finding.notesAr || '--'}
        </span>
      </div>

      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>{t('securityPatrol:patrolRecords.detail.attachment')}</span>
        <div className={`${classPrefix}__attachments`}>
          {finding.attachments.length > 0
            ? finding.attachments.map((att, idx) => {
                const src = att.absUrl || att.url
                return src ? (
                  <Image
                    key={idx}
                    src={src}
                    alt={att.name}
                    width={72}
                    height={72}
                    className={`${classPrefix}__attachment-img`}
                  />
                ) : (
                  <div
                    key={idx}
                    className={`${classPrefix}__attachment-placeholder`}
                  />
                )
              })
            : '--'}
        </div>
      </div>

      <div className={`${classPrefix}__field`}>
        <span className={`${classPrefix}__field-label`}>{t('securityPatrol:patrolRecords.detail.correctiveActions')}</span>
        <span className={`${classPrefix}__field-value`}>
          {finding.correctiveActionEn || finding.correctiveActionAr || '--'}
        </span>
      </div>

      <div className={`${classPrefix}__finding-row`}>
        <div className={`${classPrefix}__field`}>
          <span className={`${classPrefix}__field-label`}>
            {t('securityPatrol:patrolRecords.detail.responsibleDepartment')}
          </span>
          <span className={`${classPrefix}__field-value`}>
            {finding.dept || '--'}
          </span>
        </div>
        <div className={`${classPrefix}__field`}>
          <span className={`${classPrefix}__field-label`}>
            {t('securityPatrol:patrolRecords.detail.targetClosureDate')}
          </span>
          <span className={`${classPrefix}__field-value`}>
            {finding.targetClosureDate || '--'}
          </span>
        </div>
      </div>
    </div>
  )
}

// ─── QuestionItemView ─────────────────────────────────────────────────────────

const QuestionItemView = ({ item }: { item: QuestionItem }) => (
  <div className={`${classPrefix}__item`}>
    <div className={`${classPrefix}__item-row`}>
      <span className={`${classPrefix}__item-question`}>{item.question}</span>
      <AnswerBadge answer={item.answer} />
    </div>
    {item.answer === 0 && item.findings.length > 0 && (
      <div className={`${classPrefix}__findings`}>
        {item.findings.map((f, idx) => (
          <FindingView key={f.id} finding={f} index={idx} />
        ))}
      </div>
    )}
  </div>
)

// ─── SectionView ──────────────────────────────────────────────────────────────

const SectionView = ({ section }: { section: Section }) => {
  const { t } = useTranslation(['contractorPatrolRecord'])
  const [open, setOpen] = useState(section.defaultOpen)

  return (
    <div className={`${classPrefix}__section`}>
      <div
        className={`${classPrefix}__section-header${open ? ` ${classPrefix}__section-header--open` : ''}`}
        onClick={() => setOpen((v) => !v)}
      >
        <div>
          <div className={`${classPrefix}__section-no`}>
            {t('contractorPatrolRecord:category', { n: section.no })}
          </div>
          <div className={`${classPrefix}__section-title`}>{section.title}</div>
        </div>
        {open ? <IconUp /> : <IconDown />}
      </div>
      {open && section.items.length > 0 && (
        <div className={`${classPrefix}__section-body`}>
          {section.items.map((item) => (
            <QuestionItemView key={item.id} item={item} />
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Main component ───────────────────────────────────────────────────────────

const PatrolRecordDetail = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const { t } = useTranslation(['contractorPatrolRecord', 'securityPatrol', 'common'])
  const [navSel, setNavSel] = useState<NavSel>({ area: 'around' })
  const [findingCountData, setFindingCountData] = useState<any>()
  const [detailData, setDetailData] = useState<any>(null)
  const [metaData, setMetaData] = useState<any>(null)
  const [approveLog, setApproveLog] = useState<any>([])
  const [approveFlag, setApproveFlag] = useState<number>(0)
  const location = useLocation()
  const { status } = location?.state
  // const {}
  // ─── Sidebar data derived from patrolFindingCount ─────────────────────────

  const aroundApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 1,
  )
  const insideApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 2,
  )
  const parkingApiData = (findingCountData as any[] | undefined)?.find(
    (x: any) => x.type === 3,
  )

  const getInsideFloorData = (floor: FloorKey) =>
    insideApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === floor.value,
    )

  const getParkingSubData = (sub: ParkingKey) =>
    parkingApiData?.floorSummaryList?.find(
      (f: any) => f.floorCode === sub.value,
    )

  // ─── Build sections dynamically from detail API ───────────────────────────

  const dynamicSections = useMemo((): Section[] => {
    const answerList: any[] = detailData?.patrolAnswerList ?? []
    if (!answerList.length) return []
    const map = new Map<string, Section>()
    answerList.forEach((ans: any) => {
      const key = String(ans.sectionId)
      if (!map.has(key)) {
        map.set(key, {
          id: `sec-${key}`,
          no: map.size + 1,
          title: isLanguageAR
            ? ans.sectionNameAr || ans.sectionName
            : ans.sectionName,
          defaultOpen: map.size === 0,
          items: [],
        })
      }
      const findings: Finding[] =
        ans.isSituation === 0 && ans.findings?.length
          ? ans.findings.map(
              (f: any): Finding => ({
                id: String(
                  f.correctiveActionId ?? `${ans.itemId}-${Math.random()}`,
                ),
                notesAr: f.findingRemarkAr ?? '',
                notesEn: f.findingRemark ?? '',
                attachments: (f.attachmentList ?? []).map((att: any) => ({
                  url: att.url ?? '',
                  absUrl: att.absUrl ?? '',
                  name: att.fileName ?? '',
                })),
                correctiveActionAr: f.correctiveActionAr ?? '',
                correctiveActionEn: f.correctiveAction ?? '',
                dept: isLanguageAR
                  ? f.org?.orgNameAr || f.org?.orgName || ''
                  : f.org?.orgName || '',
                targetClosureDate: f.targetClosureDate ?? '',
              }),
            )
          : []
      map.get(key)!.items.push({
        id: String(ans.itemId),
        question: isLanguageAR ? ans.itemNameAr || ans.itemName : ans.itemName,
        answer: ans.isSituation === 1 ? 1 : ans.isSituation === 0 ? 0 : null,
        findings,
      })
    })
    return Array.from(map.values())
  }, [detailData, isLanguageAR])

  const contentTitle =
    navSel.area === 'around'
      ? t('securityPatrol:patrolRecords.detail.tabs.around')
      : navSel.area === 'inside'
        ? t('contractorPatrolRecord:contentTitle.insideFloor', { label: navSel.floor.label })
        : t('contractorPatrolRecord:contentTitle.parkingSub', { label: navSel.sub.label })

  // ─── API calls ────────────────────────────────────────────────────────────

  const { run: runPatrolFindingCount } = useRequest(patrolFindingCount, {
    manual: true,
    onSuccess: (res: any) => {
      setFindingCountData(res)
    },
  })

  const { run: runPatrolDetail } = useRequest(getPatrolDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setDetailData(res)
      if (!metaData) setMetaData(res)
    },
  })
  const { run: runGetApprovalDetail } = useRequest(getPatrolApprovalRecord, {
    manual: true,
    onSuccess: (res: any) => {
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag)
    },
  })

  useEffect(() => {
    if (id) {
      runPatrolFindingCount({ patrolId: id })
      runPatrolDetail({ patrolId: id, type: 1, floor: -1 })
      runGetApprovalDetail({ patrolId: id })
    }
  }, [id])

  const handleNavSel = (area: string, value?: any) => {
    let type = 1
    let floor = -1
    if (area === 'around') {
      setNavSel({ area: 'around' })
    } else if (area === 'inside') {
      setNavSel({ area: 'inside', floor: value })
      type = 2
      floor = value.value
    } else if (area === 'parking') {
      setNavSel({ area: 'parking', sub: value })
      type = 3
      floor = value.value
    }
    runPatrolDetail({ patrolId: id, type, floor })
  }
  const statusColorMap: Record<number, string> = {
    0: '#86909C',
    1: '#FF7D00',
    2: '#45AD5E',
    3: '#F53F3F',
  }
  const ApprovalType: Record<number, string> = {
    0: t('securityPatrol:status.draft'),
    1: t('securityPatrol:status.underReview'),
    2: t('securityPatrol:status.approved'),
    3: t('securityPatrol:status.rejected'),
  }

  return (
    <div className={classPrefix}>
      <ContractorHeader />

      <div className={`${classPrefix}__wrapper`}>
        <div className={`${classPrefix}__card`}>
          {/* Card header */}
          <div className={`${classPrefix}__card-header`}>
            <span className={`${classPrefix}__card-title`}>
              {t('securityPatrol:patrolRecords.detail.title')}
            </span>
            {status != null && (
              <div
                className={`${classPrefix}__status-badge`}
                style={{
                  borderColor: `${statusColorMap[status]}66`,
                  background: `${statusColorMap[status]}0D`,
                }}
              >
                <span
                  className={`${classPrefix}__status-badge-dot`}
                  style={{ background: statusColorMap[status] }}
                />
                <span
                  className={`${classPrefix}__status-badge-text`}
                  style={{ color: statusColorMap[status] }}
                >
                  {ApprovalType[status as keyof typeof ApprovalType] ?? '--'}
                </span>
              </div>
            )}
          </div>

          {/* Meta bar */}
          <div className={`${classPrefix}__meta-bar`}>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>{t('securityPatrol:patrolRecords.columns.patrolId')}</span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.code ?? '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>{t('securityPatrol:patrolRecords.columns.patrolDate')}</span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.patrolDate ?? '--'}
              </span>
            </div>

            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>{t('securityPatrol:patrolRecords.columns.shift')}</span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.shift === 1
                  ? t('securityPatrol:shift.day')
                  : metaData?.shift === 2
                    ? t('securityPatrol:shift.night')
                    : '--'}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>{t('securityPatrol:patrolRecords.columns.contractor')}</span>
              <span className={`${classPrefix}__meta-value`}>
                {isLanguageAR
                  ? metaData?.reportedByNameAr
                  : metaData?.reportedByName}
              </span>
            </div>
            <div className={`${classPrefix}__meta-item`}>
              <span className={`${classPrefix}__meta-label`}>
                {t('securityPatrol:patrolRecords.detail.patrollerName')}
              </span>
              <span className={`${classPrefix}__meta-value`}>
                {metaData?.inspector ?? '--'}
              </span>
            </div>
          </div>

          {/* Body: sidebar + main + aside */}
          <div className={`${classPrefix}__body`}>
            {/* Sidebar */}
            <div className={`${classPrefix}__sidebar`}>
              {/* Around the Building */}
              <div
                className={`${classPrefix}__nav-item${navSel.area === 'around' ? ` ${classPrefix}__nav-item--active` : ''}`}
                onClick={() => handleNavSel('around')}
              >
                <span
                  className={`${classPrefix}__nav-dot${navSel.area === 'around' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                />
                <span className={`${classPrefix}__nav-label`}>
                  {t('securityPatrol:patrolRecords.detail.tabs.around')}
                </span>
                {(aroundApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {aroundApiData.findingCount}
                  </span>
                )}
              </div>

              {/* Inside the Building group */}
              <div
                className={`${classPrefix}__nav-group-header${navSel.area === 'inside' ? ` ${classPrefix}__nav-group-header--active` : ''}`}
                onClick={() => handleNavSel('inside', INSIDE_FLOORS[0])}
              >
                <span
                  className={`${classPrefix}__nav-dot${navSel.area === 'inside' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                />
                <span className={`${classPrefix}__nav-label`}>
                  {t('securityPatrol:patrolRecords.detail.tabs.inside')}
                </span>
                {(insideApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {insideApiData.findingCount}
                  </span>
                )}
              </div>
              {INSIDE_FLOORS.map((floor) => {
                const floorData = getInsideFloorData(floor)
                const isActive =
                  navSel.area === 'inside' &&
                  navSel.floor?.value === floor.value
                return (
                  <div
                    key={floor.value}
                    className={`${classPrefix}__nav-child${isActive ? ` ${classPrefix}__nav-child--active` : ''}`}
                    onClick={() => handleNavSel('inside', floor)}
                  >
                    <span
                      className={`${classPrefix}__nav-child-dot${isActive ? ` ${classPrefix}__nav-child-dot--active` : ''}`}
                    />
                    <span className={`${classPrefix}__nav-label`}>
                      {t('securityPatrol:patrolRecords.detail.tabs.floor', { unit: floor.label })}
                    </span>
                    {(floorData?.findingCount ?? 0) > 0 && (
                      <span className={`${classPrefix}__nav-badge`}>
                        {floorData.findingCount}
                      </span>
                    )}
                  </div>
                )
              })}

              {/* Parking group */}
              <div
                className={`${classPrefix}__nav-group-header${navSel.area === 'parking' ? ` ${classPrefix}__nav-group-header--active` : ''}`}
                onClick={() => handleNavSel('parking', PARKING_SUBS[0])}
              >
                <span
                  className={`${classPrefix}__nav-dot${navSel.area === 'parking' ? ` ${classPrefix}__nav-dot--active` : ''}`}
                />
                <span className={`${classPrefix}__nav-label`}>{t('securityPatrol:patrolRecords.detail.tabs.parking')}</span>
                {(parkingApiData?.findingCount ?? 0) > 0 && (
                  <span className={`${classPrefix}__nav-badge`}>
                    {parkingApiData.findingCount}
                  </span>
                )}
              </div>
              {PARKING_SUBS.map((sub) => {
                const subData = getParkingSubData(sub)
                const isActive =
                  navSel.area === 'parking' && navSel.sub?.value === sub.value
                return (
                  <div
                    key={sub.value}
                    className={`${classPrefix}__nav-child${isActive ? ` ${classPrefix}__nav-child--active` : ''}`}
                    onClick={() => handleNavSel('parking', sub)}
                  >
                    <span
                      className={`${classPrefix}__nav-child-dot${isActive ? ` ${classPrefix}__nav-child-dot--active` : ''}`}
                    />
                    <span className={`${classPrefix}__nav-label`}>
                      {sub.label}
                    </span>
                    {(subData?.findingCount ?? 0) > 0 && (
                      <span className={`${classPrefix}__nav-badge`}>
                        {subData.findingCount}
                      </span>
                    )}
                  </div>
                )
              })}
            </div>

            {/* Main content */}
            <div className={`${classPrefix}__main`}>
              <div className={`${classPrefix}__content-title`}>
                {contentTitle}
              </div>
              <div className={`${classPrefix}__sections`}>
                {dynamicSections.map((section) => (
                  <SectionView key={section.id} section={section} />
                ))}
              </div>
            </div>

            {/* Right aside: approval panel — 暂不对接，保持原样 */}
            <div className={`${classPrefix}__aside`}>
              <ApprovalProgressCard
                title={t('contractorPatrolRecord:inspectionApproval')}
                approveLog={approveLog}
                approveFlag={null}
                // approveFlag={1}
                moduleId=''
                moduleIdKey='patrolRecordId'
                backUrl='/contractor/list'
                approvalRejected={() => Promise.resolve()}
                approvalApproved={() => Promise.resolve()}
              />
            </div>
          </div>
          {/* Footer buttons */}
          <div className={`${classPrefix}__footer`}>
            <Button icon={<IconLeft />} onClick={() => navigate(-1)}>
              {t('common:btn.back')}
            </Button>
            {status === ContractorApproval.Rejected && (
              <Button
                type='primary'
                icon={<IconEdit />}
                onClick={() => navigate(`/contractor/addOrEdit/${id}`)}
              >
                {t('common:btn.edit')}
              </Button>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

export default PatrolRecordDetail

