    flex-shrink: 0;
  }

  // ── Section cards ─────────────────────────────────────────────────────────
  &__sections {
    display: flex;
    flex-direction: column;
    gap: 12px;
  }

  &__section {
    border: 1px solid #e5e6eb;
    border-radius: 8px;
    overflow: hidden;

    &-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      min-height: 68px;
      padding: 12px 20px;
      background: #f7f8fa;
      cursor: pointer;
      user-select: none;
      transition: background-color 0.15s;

      &:hover {
        background-color: #f0f1f2;
      }

      &--open {
        border-bottom: 1px solid #e5e6eb;
      }

      .arco-icon {
        font-size: 16px;
        color: #1d2129;
        flex-shrink: 0;
      }
    }

    &-no {
      font-size: 12px;
      font-weight: 500;
      color: #30647f;
      text-transform: uppercase;
      letter-spacing: 0.3px;
      line-height: 22px;
      margin-bottom: 2px;
    }

    &-title {
      font-size: 18px;
      font-weight: 500;
      color: #1d2129;
      text-transform: uppercase;
      letter-spacing: 0.8px;
      line-height: 1.2;
    }

    &-body {
      padding: 0 20px;
      background: #fff;
    }
  }

  // ── Question items ────────────────────────────────────────────────────────
  &__item {
    padding: 20px 0;
    border-bottom: 1px solid #e5e6eb;

    &:last-child {
      border-bottom: none;
    }
  }

  &__item-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
  }

  &__item-question {
    flex: 1;
    min-width: 0;
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    line-height: 1.4;
  }

  // ── Yes / No answer badge ─────────────────────────────────────────────────
  &__answer-badge {
    flex-shrink: 0;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 64px;
    height: 28px;
    border-radius: 4px;
    color: #fff;
    font-size: 14px;
    font-weight: 500;

    &--yes {
      background: linear-gradient(to top, #30647f, #4a8099);
    }

    &--no {
      background: linear-gradient(to top, #cb3d4b, #f5626c);
    }
  }

  // ── Findings container ────────────────────────────────────────────────────
  &__findings {
    margin-top: 12px;
    background: #f7f8fa;
    border-radius: 8px;
    padding: 0 12px;
  }

  // ── Individual finding ────────────────────────────────────────────────────
  &__finding {
    padding: 16px 0;
    border-bottom: 1px solid #e5e6eb;
    display: flex;
    flex-direction: column;
    gap: 12px;

    &:last-child {
      border-bottom: none;
    }
  }

  &__finding-title {
    font-size: 15px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
  }

  &__finding-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
  }

  // ── Field label / value ───────────────────────────────────────────────────
  &__field {
    display: flex;
    flex-direction: column;
    gap: 4px;
  }

  &__field-label {
    font-size: 12px;
    color: #86909c;
    line-height: 22px;
  }

  &__field-value {
    font-size: 14px;
    color: #1d2129;
    line-height: 1.6;
  }

  // ── Attachments ───────────────────────────────────────────────────────────
  &__attachments {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
  }

  &__attachment-img {
    border-radius: 6px;
    overflow: hidden;
    border: 1px solid #e5e6eb;

    .arco-image-img {
      object-fit: cover;
    }
  }

  &__attachment-placeholder {
    width: 72px;
    height: 72px;
    border-radius: 6px;
    background: #e5e6eb;
    border: 1px solid #d0d0d0;
  }

  // ── Footer buttons ────────────────────────────────────────────────────────
  &__footer {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 16px 20px;
    border-top: 1px solid #e5e6eb;
    background: #fff;
    justify-content: end;

    .footer-back {
      border: 1px solid #e5e6eb;
      background-color: rgb(255, 255, 255);
      color: #30647f;
    }
  }

  // ── Right aside: approval panel ───────────────────────────────────────────
  &__aside {
    width: 390px;
    flex-shrink: 0;
    display: flex;
    flex-direction: column;
    // border-left: 1px solid #e5e6eb;
    overflow: hidden;

    .approval-progress-card {
      flex: 1;
      min-height: 0;
      display: flex;
      flex-direction: column;

      &__content {
        flex: 1;
        overflow-y: auto;
      }
    }
  }
}

